def corréler_tip_evenements(tip, evenements):
    """
    Corrèle des événements de logs avec la TIP.
    Retourne les événements qui impliquent des IOC connus.
    """
    hits = []

    for evt in evenements:
        # Recherche par IP
        for champ in ["src_ip", "dst_ip", "ip"]:
            ip = evt.get(champ)
            if ip:
                ioc = tip.rechercher(ip)
                if ioc:
                    hits.append({
                        "evenement": evt,
                        "ioc": ioc.to_dict(),
                        "champ": champ,
                        "score": ioc.score
                    })
        # Recherche par domaine
        domaine = evt.get("domain") or evt.get("dns_query")
        if domaine:
            ioc = tip.rechercher(domaine)
            if ioc:
                hits.append({
                    "evenement": evt,
                    "ioc": ioc.to_dict(),
                    "champ": "domain",
                    "score": ioc.score
                })

    return sorted(hits, key=lambda x: x["score"], reverse=True)

# Simulation
evts_logs = [
    {"ts": "10:00", "src_ip": "10.0.0.5",    "dst_ip": "185.220.101.3", "port": 443},
    {"ts": "10:05", "src_ip": "10.0.0.10",   "dns_query": "malware.xyz"},
    {"ts": "10:10", "src_ip": "192.168.1.1",  "dst_ip": "8.8.8.8", "port": 53},
]

hits = corréler_tip_evenements(tip, evts_logs)
print(f"\nCorrélations TIP : {len(hits)} hit(s)")
for h in hits:
    print(f"  [{h['score']}] {h['champ']}={h['ioc']['valeur']} à {h['evenement']['ts']}")
